{
	"html": {
		"value": "<div class="hero-banner">
<div class="hero-content">
<h1>Welcome to SmartCare Hospital</h1>
<p>Your health, our priority. Request services, book appointments, and access health resources &mdash; all in one place.</p>
<a class="btn btn-primary btn-lg" href="?id=sc_home"> Request a Service</a> <a class="btn btn-default btn-lg" href="?id=appointment_home"> Book Appointment</a></div>
</div>
<style>
.hero-banner {
  background: linear-gradient(135deg, #003366 0%, #006D77 100%);
  padding: 80px 40px; text-align: center; border-radius: 0 0 12px 12px;
}
.hero-banner h1 { color: #FFFFFF; font-size: 2.4em; font-weight: 700; margin-bottom: 16px; }
.hero-banner p { color: #D5E8F0; font-size: 1.1em; margin-bottom: 32px; }
.hero-banner .btn-primary { background:#F5A623; border:none; margin-right:12px; }
.hero-banner .btn-default { color:#FFFFFF; border:2px solid #FFFFFF; background:transparent; }
</style>",
